export function requireNonEmptyString(value, key, createError) {
    const trimmedValue = value.trim();
    if (!trimmedValue) {
        throw createError(`${key} must be a non-empty string.`);
    }
    return trimmedValue;
}
export function requirePositiveInteger(value, key, createError) {
    if (!Number.isInteger(value) || value < 1) {
        throw createError(`${key} must be a positive integer.`);
    }
    return value;
}
